Identify the deadlock vulnerability in this C++ mutex-locking logic and write the corrected version:
std::mutex m1, m2;
void threadA() {
    std::lock_guard<std::mutex> l1(m1);
    std::lock_guard<std::mutex> l2(m2);
}
void threadB() {
    std::lock_guard<std::mutex> l1(m2);
    std::lock_guard<std::mutex> l2(m1);
}

